def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    if ppt_diff.added_slides or ppt_diff.removed_slides:
        return f"Slides were added or removed: added={[s.slide_number for s in ppt_diff.added_slides]}, removed={[s.slide_number for s in ppt_diff.removed_slides]}.", 0.0
    if len(ppt_diff.modified_slides) > 1:
        return "More than one slide was modified.", 0.0

    orig_pr = Presentation(original_ppt_path)
    mod_pr = Presentation(modified_ppt_path)
    num_slides = min(len(orig_pr.slides), len(mod_pr.slides))
    errors = []
    for idx in range(1, num_slides):  # skip slide 0 (slide 1)
        orig_slide = orig_pr.slides[idx]
        mod_slide = mod_pr.slides[idx]
        orig_fill = orig_slide.background.fill
        mod_fill = mod_slide.background.fill
        def get_rgb(fill):
            if fill.type == 1 and fill.fore_color.rgb:
                return tuple(fill.fore_color.rgb)
            return None
        orig_rgb = get_rgb(orig_fill)
        mod_rgb = get_rgb(mod_fill)
        if orig_rgb != mod_rgb:
            errors.append(
                f"Slide {idx+1} background changed from {orig_rgb} to {mod_rgb}."
            )
    if errors:
        return ("; ".join(errors), 0.0)
    else:
        return ("No extraneous background changes detected on other slides.", 1.0)

def compute_score() -> tuple[str, float]:
    errors = []
    # Check ppt_diff for slide 1 changes (other than background)
    sid = None
    for slide in ppt_diff.modified_slides:
        orig, mod = slide
        if orig.slide_number == 1:
            sid = orig.slide_id
            # Check if only background changed
            # If more than just background changed, penalize
            orig_dict = orig.to_dict()
            mod_dict = mod.to_dict()
            # Remove background keys
            orig_bg = orig_dict.get('background', None)
            mod_bg = mod_dict.get('background', None)
            orig_dict.pop('background', None)
            mod_dict.pop('background', None)
            # Remove content hashes
            orig_dict.pop('content_hash', None)
            mod_dict.pop('content_hash', None)
            if orig_dict != mod_dict:
                errors.append(f"Slide 1 has other modified properties besides background: {orig_dict} vs {mod_dict}.")
    # Check for animations/transitions/notes/layout changes for slide 1
    # Animations
    changed_anim = [a for a in (ppt_diff.added_animations + ppt_diff.removed_animations) if a.slide_id == sid]
    if changed_anim:
        errors.append("Animations on slide 1 were added or removed.")
    changed_anim_mod = [m for m in ppt_diff.modified_animations if m[0].slide_id == sid or m[1].slide_id == sid]
    if changed_anim_mod:
        errors.append("Animations on slide 1 were modified.")
    # Transitions
    changed_trans = [t for t in (ppt_diff.added_transitions + ppt_diff.removed_transitions) if t.slide_id == sid]
    if changed_trans:
        errors.append("Transitions on slide 1 were added or removed.")
    changed_trans_mod = [m for m in ppt_diff.modified_transitions if m[0].slide_id == sid or m[1].slide_id == sid]
    if changed_trans_mod:
        errors.append("Transitions on slide 1 were modified.")
    # Notes
    orig_notes = None
    mod_notes = None
    for slide in ppt_diff.modified_slides:
        orig, mod = slide
        if orig.slide_number == 1:
            orig_notes = orig.notes
            mod_notes = mod.notes
            if orig_notes != mod_notes:
                errors.append("Notes on slide 1 were changed.")
    # Layout
    for slide in ppt_diff.modified_slides:
        orig, mod = slide
        if orig.slide_number == 1:
            if orig.layout_type != mod.layout_type:
                errors.append("Layout of slide 1 was changed.")
    if errors:
        return ("; ".join(errors), 0.0)
    else:
        return ("No extraneous non-background changes detected on slide 1.", 1.0)
